{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを正式に発足し、本日より進めることを承認した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "移行方式として、拠点をグループ分けして段階的に切り替える方法を採用することを決定した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "本番リリースの目標日を2026年9月末から変更し、2026年10月15日に延期することを決定した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "移行方式の再検討に伴い、外部ライセンス費用の再見積もりを2026年6月1日までに取得することとした。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "サクラ商事さんとの認証・マスタ配信共同利用の承認を得たため、第3案（共同利用）を採用し、自前構築（第1案）を見送ることとした。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "ベンダー調達先としてコマツバ・ソリューションズを選定した（ハギワラ技研とツヅキシステムは見送り）。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "ベンダー見積の社内稟議起票を2026年5月18日までに完了することとした。",
      "decided_by": "郡司 明久"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "API仕様書のドラフト（エンドポイント一覧と主要項目のレイアウトを含む）を作成し、2026年5月20日までに共有する。",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A2",
      "task": "検証環境のサーバ調達依頼を提出し、調達の可否を確認する。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "ヒアリングの対象部署リスト（および想定の窓口）を作成して共有する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A4",
      "task": "サクラ商事さんへの共同利用承認に関する回答書を作成・送付する。",
      "assignee": "桐生 遥",
      "due": "2026-05-13"
    },
    {
      "id": "A5",
      "task": "外部ライセンス費用の再見積もりを依頼し、年契約との比較条件も確認して結果を出す。",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A6",
      "task": "移行テスト計画を作成する（切り戻し手順等の観点を含む）。",
      "assignee": "芦田 巧",
      "due": "2026-06-03"
    },
    {
      "id": "A7",
      "task": "負荷テスト計画を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A8",
      "task": "移行リハーサルの手順書（負荷試験環境構築も含む）を作成し、QAレビューを受ける。",
      "assignee": "沼田 賢一",
      "due": "2026-06-05"
    },
    {
      "id": "A9",
      "task": "既存のテストケースを棚卸し（生きているもの、捨てるもの、修正が必要なものの分類）を行う。",
      "assignee": "白鳥 千夏",
      "due": "2026-05-31"
    },
    {
      "id": "A10",
      "task": "移行方式の決定に伴う全拠点の説明会日程を調整し、案を出して共有する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-27"
    },
    {
      "id": "A11",
      "task": "拠点別の生産管理担当者へのヒアリング対象リストを回すため、各拠口に連絡する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A12",
      "task": "移行方式のグループ分け案を作成・整理し、詳細を固める。",
      "assignee": "芦田 巧",
      "due": "2026-05-31"
    },
    {
      "id": "A13",
      "task": "移行リハーサルの手順書をレビューする。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-05"
    }
  ],
